INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'mess', 'Mess > Timings: Breakfast 07:15-09:15 AM, Lunch 12:00-01:45 PM, Snacks 05:00-05:45 PM, Dinner 07:30-09:15 PM.');
