INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'mess', 'Mess > Common items at Lunch: Zeera Rice, Roti, Hard Dal, Sambhar, Pickle. Common items at Dinner: Rice, Roti, Hard Dal, Sambhar, Pickle.');
