INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'mess', 'Mess > Sprout Mix: One large spoon (Moong, chickpea, peas, onion, mustard, mixed masala). Salad: Cucumber, Tomato, Carrot, Radish.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'mess', 'Mess > Portions: Curd 100ml, Milk 150ml, Cornflakes 50g, Tea 70ml, Paneer 75g, Mushroom 30g, Egg 2pcs, Chicken 120g (2pcs).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'mess', 'Mess > Notes: Orange must be large and premium quality. Tea/coffee portions fixed for day, no substitutions. Food items must remain available throughout serving duration. Running out of any item is strictly prohibited. Any breach leads to penalties/compensation on caterer.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'mess', 'Mess > Cuisine: Mix of Odia (Ghanta Curry, Dalma), North Indian (Paneer dishes, Biryani), and South Indian items. Both veg and non-veg options available at dinner. Non-veg includes fish, chicken, and egg dishes.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Program: B.Tech 2025-26 at NIT Rourkela.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Semester 1: Rs 1,36,500. Includes Admission Rs 2,500, Tuition Rs 62,500, Other Fees Rs 5,000, Student Activity Rs 2,000, Medical Rs 2,000, Hostel Rs 5,000, Caution Money Rs 10,000 (refundable), Institute Emergency Fund Rs 12,500 (one-time), Hall Establishment Rs 5,000, Mess Advance Rs 30,000.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Semester 2: Rs 1,11,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Semester 3: Rs 1,11,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Semester 4: Rs 1,11,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Semester 5: Rs 1,11,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Semester 6: Rs 1,11,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Semester 7: Rs 1,14,500. Includes Souvenir Rs 500 and Convocation Rs 2,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Semester 8: Rs 1,11,500.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Total 4-year B.Tech: Rs 1,36,500 + Rs 1,11,500 x 6 + Rs 1,14,500 = Rs 9,20,000 approximately.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > SC/ST/PH Waiver: Students from SC/ST/PH categories or family income below Rs 1 lakh get complete tuition fee exemption at NIT Rourkela.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Partial Waiver: Students with family income between Rs 1-5 lakh pay 1/3rd tuition fee = Rs 20,833 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Other fees include Examination, Library, and Electricity charges.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Rourkela', 'fee_structure', 'Fee Structure > Mess advance of Rs 30,000 per semester is approximate.');
